/*
* @name FilterMachineParameterByName
* @date 14.10.2022
* @author Wilfrid Azariah CAD-IT
* @param textFilter	STRING
* @param machineParameterData	INFOTABLE "HPMC.AddOn.RTMP.Management.DS"
* @return infotable "HPMC.AddOn.RTMP.Management.DS"
* info : service to filter machine parameter data based on the parameter name
*
* [14.10.2022] [Wilfrid Azariah] initial development
*/
var debugging = 0;
var result;
var loggerBeginning = "["+me.name+":FilterMachineParameterByName]";
 logger.info(loggerBeginning + " machineParameterData length is  "+machineParameterData.length);
(function(){
    "use strict";
    logger.info(loggerBeginning + " start to get filtered machine parameter data. ");
    try{
        //debugging only
        if (debugging) {
            //locations = Things["HPMC.WorldMap.Helper"].QueryAllLocation();
        }
        if (nameFilter===undefined || nameFilter===null){
            nameFilter='';
        }

        result = Resources["InfoTableFunctions"].Query({
            t: machineParameterData /* INFOTABLE */ ,
            query: 
            {
                "filters": {
                        "type": "LIKE",
                        "fieldName": "ParameterName",
                        "value": "*"+nameFilter+"*"
                }	
            } /* QUERY */
        });
        //Replace value in no column
        for (var i=0; i<result.length;i++) {
            result.rows[i].No = i+1;
        }
        logger.info(loggerBeginning + " FilterMachineParameterByName Result length is  "+result.length);
    	logger.info(loggerBeginning + " success to get filtered machine parameter data. ");
    } catch(error){
    	logger.error(loggerBeginning + " failed to get filtered machine parameter data - [ERROR]: " + error);
    }
}());


