/*
* @name GetLastMachineParameterPIC
* @date 17.10.2022
* @author Wilfrid Azariah CAD-IT
* @param selectedPIC	STRING 
* @param machineParameterPIC	INFOTABLE "HPMC.AddOn.DropdownData.DS"
* @return INFOTABLE "HPMC.AddOn.DropdownData.DS"
* info : service to get select machine parameter PIC(s) from the list
*
* [17.10.2022] [Wilfrid Azariah] initial development
*/
var result;
var loggerBeginning = "["+me.name+":GetLastMachineParameterPIC]";
(function(){
    "use strict";
    logger.info(loggerBeginning + " start to get list of selected machine parameter PIC.");
    try{
        // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.AddOn.DropdownData.DS)
        let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
            infoTableName: "InfoTable",
            dataShapeName: "HPMC.Core.DropdownData.DS"
        });

		var nameArr = selectedPIC.split(',');
        var onePIC;
        let newEntry = new Object();
        for (var i = 0; i < nameArr.length; i++) {
            if (nameArr[i].charAt(0) === " ") {
                nameArr[i] = nameArr[i].slice(1);
            }
            onePIC = Resources["InfoTableFunctions"].Query({
                t: machineParameterPIC /* INFOTABLE */ ,
                query: 
                {
                    "filters": {
                            "type": "LIKE",
                            "fieldName": "dropdown_value",
                            "value": "*"+nameArr[i]+"*"
                    }	
                } /* QUERY */
            });
            newEntry.dropdown_id = onePIC[0].dropdown_id;
            newEntry.dropdown_value = onePIC[0].dropdown_value;
            data.AddRow(newEntry);
        }

        result = data;

    	logger.info(loggerBeginning + " success to get list of selected machine parameter PIC.");
    } catch(error){
    	logger.error(loggerBeginning + " failed to get list of selected machine parameter PIC - [ERROR]: " + error);
    }
}());


