/*
* @name GetMachineParameter
* @date 18.10.2022
* @author Wilfrid Azariah CAD-IT
* @param selectedMachineIds	INFOTABLE "HPMC.AddOn.Asset.Saw.Complete.DS"
* @return infotable "HPMC.AddOn.RTMP.Management.DS"
* info : service to get machine parameter data
*
* [18.10.2022] [Wilfrid Azariah] initial development
*/

var result;
var loggerBeginning = "["+me.name+":GetMachineParameter]";
logger.info(loggerBeginning + " GetMachineParameter selectedMachineIds are length . "+selectedMachineIds.length);
(function(){
    "use strict";
    logger.info(loggerBeginning + " start to get machine parameter data. ");
    try{
        // CreateInfoTableFromDataShape(infoTableName:STRING("InfoTable"), dataShapeName:STRING):INFOTABLE(HPMC.AddOn.RTMP.Management.DS)
        let data = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
            infoTableName: "InfoTable",
            dataShapeName: "HPMC.AddOn.RTMP.Management.DS"
        });


        let machineIdList = "''";

        // Convert selectedMachineIds to machineIdList
        selectedMachineIds = (selectedMachineIds === null || selectedMachineIds === undefined) ? "" : selectedMachineIds;
        if (selectedMachineIds.length > 0) {
            for (var i = 0; i < selectedMachineIds.length; i++) {
                machineIdList += ", '" + selectedMachineIds.rows[i].machineId + "'";
			}
        }

        // let MachineInfo = Resources["InfoTableFunctions"].CreateInfoTableFromDataShape({
        //     infoTableName: "EmailData",
        //     dataShapeName: "HPMC.AddOn.RTMP.EmailDataFields.DS"
        // });


        // // Add the new row
        // MachineInfo.AddRow({
        //     MachineId: machineId,          // STRING
        //     ParameterId: parameterId,      // STRING
        // //  name: nameString,                    // STRING
        //     email: email,                  // STRING
        //     UpperBound: upperBound,        // NUMBER
        //     LowerBound: lowerBound,        // NUMBER
        //     parameterValue: machineRow.parameter_value || 0  // NUMBER
        // });

		const temp = me.QueryMachineParameter({
            machineIdList: machineIdList /* STRING */
        });

        // HPMC.Management.RTMP.DS entry object
        let newEntry = new Object();
        for (var i = 0; i < temp.length; i++) {
            newEntry.No = i + 1; // INTEGER
            newEntry.MachineName = temp.rows[i].machine_id.split("_")[1] + '-' + temp.rows[i].machine_name; // STRING
            newEntry.ParameterName = temp.rows[i].parameter_name; // STRING
            newEntry.Unit = temp.rows[i].unit; // STRING
            newEntry.Description = temp.rows[i].parameter_desc; // STRING
            newEntry.Status = temp.rows[i].status; // STRING
            newEntry.UpperBound = temp.rows[i].upper_bound;
            newEntry.LowerBound = temp.rows[i].lower_bound;
            newEntry.ParameterId = temp.rows[i].rtmp_master_id;
            newEntry.PIC = temp.rows[i].pic;
          //  newEntry.PIC = email;
            newEntry.Message = temp.rows[i].message; // STRING
            data.AddRow(newEntry);
        }

        for (let i =0;i<data.length;i++){
            let rowData = data.rows[i];
            //get language from user config
            let currentLanguage = Resources['CurrentSessionInfo'].GetCurrentUserLanguage();
            if (rowData.Status!=="" && rowData.Status!==null && rowData.Status!==undefined){
                // get token value from language
                let token = Resources['RuntimeLocalizationFunctions'].GetEffectiveTokenForLanguage({
                    language: currentLanguage /* STRING */ ,
                    token: "HPMC.ParameterStatus." + rowData.Status.split(" ").join("") /* STRING */ ,
                });
                data.rows[i].Status = token ;//+ data.dropdown_value;
            }
            if (rowData.ParameterName!=="" && rowData.ParameterName!==null && rowData.ParameterName!==undefined){
                // get token value from language
                let token = Resources['RuntimeLocalizationFunctions'].GetEffectiveTokenForLanguage({
                    language: currentLanguage /* STRING */ ,
                    token: "HPMC.Parameter." + rowData.ParameterName.split(" ").join("") /* STRING */ ,
                });
                data.rows[i].ParameterName = token ;//+ data.dropdown_value;
            }
        }

        result = data;

    	logger.info(loggerBeginning + " success to get machine parameter data. ");
    } catch(error){
    	logger.error(loggerBeginning + " failed to get machine parameter data - [ERROR]: " + error);
    }
}());


