/*
* @name GetMachineParameterSorted
* @date 17.10.2022
* @author Wilfrid Azariah CAD-IT
* @param queryFilter	QUERY
* @param gridData		INFOTABLE "HPMC.AddOn.RTMP.Management.DS"
* @return infotable "HPMC.AddOn.RTMP.Management.DS"
* info : service to sort machine parameter data
*
* [17.10.2022] [Wilfrid Azariah] initial development
*/

var result;
var loggerBeginning = "["+me.name+":GetMachineParameterSorted]";
(function(){
    "use strict";
    logger.info(loggerBeginning + " start to sort machine parameter data. ");
    logger.info(loggerBeginning + " input in gridData "+gridData.length);
    try{
        let tempTable = gridData; // dataShape: "HPMC.AddOn.RTMP.Management.DS"

        result = tempTable;
        if (queryFilter==null || queryFilter==undefined ||queryFilter=="")
        	result.Sort({name:"MachineName",ascending:true});
        else {
        	result = Resources["InfoTableFunctions"].Query({
                t: tempTable /* INFOTABLE */,
                query: {"sorts":queryFilter.sorts}
            });
        }
        for (let i = 0; i < result.length; i++) {
            result[i].No = i + 1;
        }

    	logger.info(loggerBeginning + " success to sort machine parameter data. ");
    } catch(error){
    	logger.error(loggerBeginning + " failed to sort machine parameter data - [ERROR]: " + error);
    }
}());


